import pdfplumber
import re

def extract_insurance_invoices(filepath):
    """Extract insurance invoice data from PDF"""
    invoices = []
    with pdfplumber.open(filepath) as pdf:
        text = ""
        for page in pdf.pages:
            text += page.extract_text() + "\n"

    # Split by "INVOICE" to get individual invoices
    invoice_blocks = re.split(r'INVOICE\s+', text)

    for block in invoice_blocks[1:]:  # Skip first empty block
        lines = [l.strip() for l in block.split('\n') if l.strip()]
        if len(lines) < 2:
            continue

        vendor = lines[0]

        # Extract invoice number and date
        invoice_num = None
        invoice_date = None
        for line in lines:
            if 'Invoice #' in line:
                match = re.search(r'Invoice #:\s*(\d+)', line)
                if match:
                    invoice_num = match.group(1)
            if 'Date:' in line:
                match = re.search(r'Date:\s*(\d{1,2}/\d{1,2}/\d{4})', line)
                if match:
                    invoice_date = match.group(1)

        # Extract amount
        amount = None
        for line in lines:
            if '$' in line:
                match = re.search(r'\$([\d,]+\.?\d*)', line)
                if match:
                    amount_str = match.group(1).replace(',', '')
                    amount = float(amount_str)
                    break

        if amount and invoice_date:
            invoices.append({
                'vendor': vendor,
                'invoice_num': invoice_num,
                'invoice_date': invoice_date,
                'amount': amount
            })

    return invoices

insurance_invoices = extract_insurance_invoices('Aurisic_Prepaid_Insurance.pdf')

print(f"Insurance invoices found: {len(insurance_invoices)}")
print(f"Total amount: ${sum(i['amount'] for i in insurance_invoices):,.2f}")

print("\n=== Insurance Invoices ===")
for inv in insurance_invoices:
    print(f"{inv['invoice_date']:10} | {inv['vendor']:20} | ${inv['amount']:>12,.2f} | #{inv['invoice_num']}")
EOF"}

